export const runtime = "edge"

export async function GET(request: Request, { params }: { params: { id: string } }) {
  try {
    const id = params.id

    console.log("🏪 맛집 상세 정보 요청:", id)

    // Mock 상세 데이터
    const mockDetail = {
      id: Number.parseInt(id),
      company_id: `CMP-${id}`,
      name: `맛집 ${id}`,
      branch_name: "본점",
      category_large: "음식",
      category_middle: "한식",
      category_small: "한정식",
      address: "서울특별시 강남구 테헤란로 123",
      building_name: "맛집빌딩",
      latitude: 37.123456,
      longitude: 127.123456,
    }

    return Response.json({
      success: true,
      data: mockDetail,
    })
  } catch (error) {
    console.error("맛집 상세 정보 조회 에러:", error)
    return Response.json(
      {
        success: false,
        error: "맛집 상세 정보 조회에 실패했습니다",
      },
      { status: 500 },
    )
  }
}
